import heapq
def k_closest(points, k):
    heap = []
    for x, y in points:
        d = x*x + y*y
        item = (-d, x, y)
        if len(heap) < k:
            heapq.heappush(heap, item)
        else:
            if item > heap[0]:
                heapq.heapreplace(heap, item)
    return [[x, y] for _, x, y in heap]

